Set-StrictMode -Version 2.0
function Get-GodModeToolProbeArgs { param([string]$Name) switch($Name){ 'where'{@('/?')} 'cmd'{@('/c','ver')} 'powershell'{@('-NoProfile','-Command','$PSVersionTable.PSVersion.ToString()')} default{@('--version')} } }
function Resolve-GodModeTools { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $map=@{schema_version=1;generated_at=Get-GodModeIso;tools=@{};broken_helpers=@();selected_summary=@{}}; foreach($t in @('codex','node','npm','npx','rg','git','gh','python','py','pwsh','powershell','dotnet','code','wsl','cmd','where')){ $c=@(); try{Get-Command -All $t -ErrorAction SilentlyContinue|%{$c+=@{source=$_.Source;command_type=$_.CommandType.ToString();from='Get-Command'}}}catch{}; try{& where.exe $t 2>$null|%{if($_){$c+=@{source=$_;command_type='Application';from='where.exe'}}}}catch{}; $seen=@{}; $ded=@(); foreach($x in $c){ if($x.source -and -not $seen.ContainsKey($x.source)){ $seen[$x.source]=$true; $ded+=$x } }; $sel=$null; $probe=@{exit_code=$null;stdout='';stderr='';timed_out=$false}; foreach($x in $ded){ try{$rr=Invoke-GodModeNativeCommand $x.source (Get-GodModeToolProbeArgs $t) (Resolve-GodModeProjectPath $Project) 8}catch{$rr=@{exit_code=-9;stdout='';stderr=$_.Exception.Message;timed_out=$false}}; if($rr.exit_code -eq 0 -or $t -in @('where','code')){ $sel=$x.source; $probe=@{exit_code=$rr.exit_code;stdout=($rr.stdout.Substring(0,[Math]::Min(400,$rr.stdout.Length)));stderr=($rr.stderr.Substring(0,[Math]::Min(400,$rr.stderr.Length)));timed_out=$rr.timed_out}; break } elseif($x.source -match 'WindowsApps'){ $map.broken_helpers += @{tool=$t;path=$x.source;exit_code=$rr.exit_code;stderr=$rr.stderr} } }; $map.tools[$t]=@{selected_path=$sel;candidates=$ded;probe=$probe;verified=[bool]$sel;windowsapps_path_risk=($sel -match 'WindowsApps')}; $map.selected_summary[$t]=$sel }; Write-GodModeJsonAtomic (Join-GodModePath $r 'state/tool-map.json') $map|Out-Null; $map }
